  insert into public.planes_nutricionales (id, usuario_id, datos) values ('plan-valentina', v_valentina, replace(replace($semilla${"id":"plan-valentina","usuarioId":"u-valentina","analisis":"TDEE estimado en 2050 kcal con NEAT medio (9-10k pasos). Objetivo: recomposición con déficit ligero ondulado. Proteína alta constante (1.9 g/kg), carbohidrato ondulado según día de entrenamiento. Peso bajando ~0.15 kg/semana con perímetro de glúteo subiendo: la recomposición va en la dirección correcta.","macrosPorDia":{"ALTO":{"kcal":2100,"proteinaG":115,"carbosG":240,"grasaG":62},"BAJO":{"kcal":1750,"proteinaG":115,"carbosG":160,"grasaG":60},"CHEAT":{"kcal":2400,"proteinaG":110,"carbosG":300,"grasaG":75}},"menus":[{"nombre":"Menú 1 · Día ALTO (entreno fuerte)","tipoDia":"ALTO","comidas":[{"hora":"6:30","titulo":"Desayuno · overnight oats","alimentos":["70 g avena","200 ml leche semidescremada","1 scoop proteína","100 g fresas","10 g mantequilla de maní"],"nota":"Prepáralo la noche anterior"},{"hora":"10:00","titulo":"Media mañana","alimentos":["1 banano","30 g almendras"]},{"hora":"13:00","titulo":"Almuerzo · meal prep","alimentos":["150 g pechuga de pollo","200 g arroz cocido","Ensalada verde con 1 cdta aceite de oliva","100 g plátano maduro"]},{"hora":"16:30","titulo":"Pre-entreno","alimentos":["40 g arepa de maíz","2 claras + 1 huevo"],"nota":"60-90 min antes de entrenar"},{"hora":"20:30","titulo":"Post-entreno / cena","alimentos":["150 g tilapia","250 g papa criolla","Verduras salteadas"],"nota":"La comida más grande del día después de entrenar"}]},{"nombre":"Menú 2 · Día BAJO (descanso)","tipoDia":"BAJO","comidas":[{"hora":"7:00","titulo":"Desayuno","alimentos":["3 huevos revueltos","50 g arepa","1/2 aguacate pequeño"]},{"hora":"12:30","titulo":"Almuerzo · ensalada potente","alimentos":["150 g atún en agua","Base de espinaca y lechuga","100 g quinua cocida","1 cda aceite de oliva"]},{"hora":"16:00","titulo":"Snack","alimentos":["1 yogur griego natural","80 g arándanos"]},{"hora":"20:00","titulo":"Cena ligera","alimentos":["150 g pechuga a la plancha","Crema de verduras sin crema de leche"]}]},{"nombre":"Menú 3 · Día CHEAT controlado","tipoDia":"CHEAT","comidas":[{"hora":"7:30","titulo":"Desayuno normal","alimentos":["Igual al día BAJO"],"nota":"El cheat es UNA comida, no un día entero"},{"hora":"13:00","titulo":"Comida libre","alimentos":["Lo que elijas: hamburguesa, pizza, bandeja paisa..."],"nota":"Disfrútala sin culpa y sin repetir"},{"hora":"20:00","titulo":"Cena de vuelta al plan","alimentos":["150 g proteína magra","Verduras al gusto"]}]}],"equivalencias":[{"grupo":"Proteínas","base":"150 g pechuga de pollo","opciones":["150 g tilapia o basa","140 g lomo de cerdo magro","150 g atún","3 huevos + 3 claras","1.5 scoop de proteína"]},{"grupo":"Carbohidratos","base":"200 g arroz cocido","opciones":["250 g papa cocida","220 g pasta cocida","150 g plátano maduro","80 g avena en seco","100 g arepa de maíz"]},{"grupo":"Grasas","base":"1 cda aceite de oliva","opciones":["30 g almendras o maní","1/2 aguacate pequeño","15 g mantequilla de maní"]}],"listaCompras":["Pechuga de pollo (1.5 kg)","Tilapia (1 kg)","Huevos (30)","Avena (1 kg)","Arroz (2 kg)","Papa y papa criolla (2 kg)","Plátano y banano","Fresas y arándanos","Espinaca, lechuga, brócoli, zanahoria","Yogur griego natural (4)","Leche semidescremada (2 L)","Almendras y maní (500 g)","Aceite de oliva","Proteína en polvo (si queda poca)"],"suplementacion":["Creatina monohidrato 5 g diarios (cualquier hora, todos los días)","Omega-3 (EPA+DHA) 2 g con el almuerzo","Vitamina D 2000 UI con el desayuno","Cafeína 150-200 mg pre-entreno opcional (no después de las 5 pm)"],"seccionesEspeciales":[{"titulo":"Ciclo menstrual y entrenamiento","contenido":"En fase lútea tardía es normal más hambre, más retención y menos fuerza: no es pérdida de progreso. Esa semana prioriza el sueño, sube pasos suaves y usa las equivalencias para mantener adherencia sin rigidez. El peso de la báscula puede subir 0.5-1 kg por agua: mira la tendencia de 2 semanas, no el día."}]}$semilla$, 'u-bryan', v_coach::text), 'u-valentina', v_valentina::text)::jsonb);
