  insert into public.cuestionarios (id, datos, asignado_a) values ('q-dolor-articular', replace(replace($semilla${"id":"q-dolor-articular","titulo":"Chequeo de dolor articular","descripcion":"Ayúdanos a detectar molestias a tiempo para ajustar tu programación antes de que se vuelvan un problema.","asignadoA":["u-valentina"],"preguntas":[{"id":"p1","tipo":"si_no","enunciado":"¿Sentiste dolor (no agujetas) en alguna articulación esta semana?"},{"id":"p2","tipo":"opcion_multiple","enunciado":"Si hubo molestia, ¿dónde?","opciones":["Hombro","Codo","Muñeca","Cadera","Rodilla","Zona lumbar","No aplica"]},{"id":"p3","tipo":"escala_1_5","enunciado":"Del 1 al 5, ¿qué tan intensa fue la molestia en su peor momento?"},{"id":"p4","tipo":"si_no","enunciado":"¿La molestia apareció durante un ejercicio específico?"},{"id":"p5","tipo":"texto","enunciado":"Cuéntanos en qué ejercicio y en qué parte del movimiento la sentiste"}]}$semilla$, 'u-bryan', v_coach::text), 'u-valentina', v_valentina::text)::jsonb, array[v_valentina]) on conflict (id) do update set datos = excluded.datos, asignado_a = excluded.asignado_a;
  insert into public.cuestionarios (id, datos, asignado_a) values ('q-adherencia-bloque', replace(replace($semilla${"id":"q-adherencia-bloque","titulo":"Adherencia y disfrute del bloque","descripcion":"Tu opinión define el siguiente bloque: lo que disfrutas se sostiene, y lo que se sostiene da resultados.","asignadoA":["u-valentina"],"preguntas":[{"id":"p1","tipo":"escala_1_5","enunciado":"¿Qué tan sostenible sientes el plan de entrenamiento actual?"},{"id":"p2","tipo":"escala_1_5","enunciado":"¿Qué tan sostenible sientes el plan de nutrición actual?"},{"id":"p3","tipo":"opcion_multiple","enunciado":"¿Qué sesión disfrutas más?","opciones":["LEG A","UPPER A","LEG B","UPPER B","FULL C"]},{"id":"p4","tipo":"texto","enunciado":"¿Qué cambiarías del bloque actual?"}]}$semilla$, 'u-bryan', v_coach::text), 'u-valentina', v_valentina::text)::jsonb, array[v_valentina]) on conflict (id) do update set datos = excluded.datos, asignado_a = excluded.asignado_a;
