  insert into public.contenidos (id, datos) values ('c-rir', replace(replace($semilla${"id":"c-rir","tipo":"articulo","categoria":"Educación","titulo":"¿Qué es el RIR y por qué lo usamos?","descripcion":"RIR = repeticiones en reserva. Si dice RIR 2, terminas la serie pudiendo hacer 2 reps más con buena técnica. Así controlamos qué tan cerca del fallo entrenas sin quemarte: las últimas 5 reps antes del fallo son las que más músculo construyen, pero vivir en el fallo dispara la fatiga y frena tu progreso. Sé honesta con el número: registra el RIR real de cada serie, incluso si fue 0.","url":""}$semilla$, 'u-bryan', v_coach::text), 'u-valentina', v_valentina::text)::jsonb) on conflict (id) do update set datos = excluded.datos;
  insert into public.contenidos (id, datos) values ('c-ondulacion', replace(replace($semilla${"id":"c-ondulacion","tipo":"articulo","categoria":"Educación","titulo":"¿Por qué tu plan cambia cada 8 días?","descripcion":"Tu cuerpo se adapta a lo que repites. Por eso ondulamos cargas, repeticiones y volumen microciclo a microciclo: cada 8 días ajustamos la dosis según lo que registraste — tus cargas reales, tu RIR, tu sueño, tu estrés. No es un plan genérico de 12 semanas: es una conversación entre tus datos y tu programación.","url":""}$semilla$, 'u-bryan', v_coach::text), 'u-valentina', v_valentina::text)::jsonb) on conflict (id) do update set datos = excluded.datos;
  insert into public.premiaciones (id, usuario_id, titulo, fecha, nota) values ('prem-1', v_valentina, 'Mejor progresión del mes', '2026-06-30', 'Junio: +5 kg en hip thrust, adherencia nutricional del 92% y todos los check-ins al día. Disciplina de otra categoría.');
