-- App Alpha Athletics · Semilla de datos de prueba (generada 2026-07-17)
-- 1. EDITA los dos correos de la sección CONFIGURA (deben ser los de las cuentas
--    que creaste en Authentication → Users).
-- 2. Pega TODO en Supabase → SQL Editor → New query → Run.
-- Es seguro correrla varias veces: borra y recarga los datos de prueba.

do $bloque$
declare
  -- ══════════ CONFIGURA: tus dos correos ══════════
  correo_coach     constant text := 'TU-CORREO@AQUI.com';
  correo_valentina constant text := 'CORREO-DE-PRUEBA@AQUI.com';
  -- ═══════════════════════════════════════════════
  v_coach uuid;
  v_valentina uuid;
begin
  select id into v_coach from auth.users where email = correo_coach;
  select id into v_valentina from auth.users where email = correo_valentina;
  if v_coach is null then raise exception 'No existe una cuenta con el correo del coach: %', correo_coach; end if;
  if v_valentina is null then raise exception 'No existe una cuenta con el correo de prueba: %', correo_valentina; end if;

  -- Nombres y roles
  update public.usuarios_app set rol = 'coach', nombre = 'Bryan', avatar_iniciales = 'B' where id = v_coach;
  update public.usuarios_app set nombre = 'Valentina Cruz', avatar_iniciales = 'VC' where id = v_valentina;

  -- Limpieza de datos de prueba previos (solo de estas dos cuentas)
  delete from public.perfiles where usuario_id in (v_coach, v_valentina);
  delete from public.microciclos where usuario_id in (v_coach, v_valentina);
  delete from public.checkins where usuario_id in (v_coach, v_valentina);
  delete from public.adherencias where usuario_id in (v_coach, v_valentina);
  delete from public.planes_nutricionales where usuario_id in (v_coach, v_valentina);
  delete from public.respuestas where usuario_id in (v_coach, v_valentina);
  delete from public.premiaciones where usuario_id in (v_coach, v_valentina);
  delete from public.mensajes where de_id in (v_coach, v_valentina) and para_id in (v_coach, v_valentina);

  -- Perfil

  -- Microciclos

  -- Check-ins de bienestar

  -- Plan nutricional y adherencia

  -- Chat coach ↔ asesorada

  -- Cuestionarios, respuestas, contenidos y premiaciones

  raise notice 'Semilla cargada: perfil, % microciclos, % check-ins, % mensajes.', 2, 12, 4;
end
$bloque$;
